={{
{
  model: "openai/gpt-oss-120b",
  temperature: 0.2,
  response_format: { type: "json_object" },
  messages: [
    {
      role: "system",
      content: "You are an intelligent email classification system for an engineering student actively learning software development, applying for internships, attending college, and participating in coding activities."
    },
    {
      role: "user",
      content:
`EMAIL:
Sender: ${$json.sender_name} <${$json.sender_email}>
Subject: ${$json.subject}
Gmail's own category signal (informational only, may be unreliable — do not treat as ground truth): ${$json.gmail_category_hint || 'none'}
Body:
${$json.email_body_clean}

Classify this email and return ONLY a valid JSON object with exactly these fields, no markdown, no explanation, no code fences:

{
  "category": one of ["CAREER","COLLEGE","PERSONAL","FINANCE","PROMOTION","NEWSLETTER","AUTOMATED","OTHER"],
  "importance": one of ["HIGH","MEDIUM","LOW"],
  "urgency_score": integer from 1 to 10,
  "action_required": true or false,
  "deadline_detected": "YYYY-MM-DD" or null,
  "reason": "one sentence explaining the classification",
  "summary": "one sentence summary of the email",
  "event_datetime": "YYYY-MM-DDTHH:MM:SS" or null,
  "event_type": one of ["CONTEST", "DEADLINE", "NONE"]
}

Guidance:
- CAREER: internship communication, job applications, recruiter emails, interview invitations, coding assessments, application updates, placement opportunities, hackathons, technical opportunities. Recruitment and hiring emails are CAREER, not PROMOTION, even if they contain marketing-style language or come from a corporate careers page.
- COLLEGE: exams, assignments, faculty communication, attendance, academic projects, college deadlines, placement cell communication.
- If the email announces a coding contest, hackathon, or competitive programming event with a specific start time, set event_type to "CONTEST" and event_datetime to that start time in ISO format.
- If the email states an assignment, application, or task deadline with a specific date (and time if mentioned), set event_type to "DEADLINE" and event_datetime accordingly. If only a date is given with no time, use 23:59:00 as the time.
- If no specific date/time is mentioned, set event_type to "NONE" and event_datetime to null.
- Assume IST (India Standard Time) if no timezone is specified.
- PROMOTION: marketing, discounts, product ads, subscription upsells (e.g. "buy now", "50% off", "upgrade to premium"). Do NOT classify recruitment, job, or internship emails as PROMOTION even if they use persuasive language.
- Security alerts, immediate deadlines, payment failures, interview deadlines, and account problems should receive a HIGH urgency_score (8-10).
- Ignore Gmail's own category signal if it conflicts with the actual content of the email — Gmail's categorization is known to be unreliable, especially for forwarded emails.
- Return ONLY the JSON object. No prose before or after it.`
    }
  ]
}
}}

parameters.jsCode:
const item = $input.first().json;

const VALID_CATEGORIES = [
  "CAREER",
  "COLLEGE",
  "PERSONAL",
  "FINANCE",
  "PROMOTIONS",
  "NEWSLETTER",
  "AUTOMATED",
  "OTHER"
];

const VALID_IMPORTANCE = [
  "HIGH",
  "MEDIUM",
  "LOW"
];

const errors = [];
const warnings = [];

/* ---------------- Parse Check ---------------- */

if (item.parse_error === true) {
  errors.push(`JSON parse failed: ${item.parse_error_message || "Unknown parse error"}`);
}

/* ---------------- Category ---------------- */

if (!VALID_CATEGORIES.includes(item.category)) {
  warnings.push(`Unknown category "${item.category}". Defaulted to OTHER.`);
  item.category = "OTHER";
}

/* ---------------- Importance ---------------- */

if (!VALID_IMPORTANCE.includes(item.importance)) {
  warnings.push(`Unknown importance "${item.importance}". Defaulted to MEDIUM.`);
  item.importance = "MEDIUM";
}

/* ---------------- Urgency ---------------- */

let urgency = Number(item.urgency_score);

if (!Number.isInteger(urgency)) {
  warnings.push("urgency_score was not an integer. Defaulted to 5.");
  urgency = 5;
}

urgency = Math.max(1, Math.min(10, urgency));

/* ---------------- Boolean ---------------- */

if (typeof item.action_required !== "boolean") {
  warnings.push("action_required was not boolean. Defaulted to false.");
  item.action_required = false;
}

/* ---------------- Deadline ---------------- */

if (item.deadline_detected !== null &&
    item.deadline_detected !== undefined &&
    item.deadline_detected !== "") {

    const valid =
        /^\d{4}-\d{2}-\d{2}$/.test(item.deadline_detected) &&
        !isNaN(Date.parse(item.deadline_detected));

    if (!valid) {
        warnings.push("Invalid deadline format. Cleared.");
        item.deadline_detected = null;
    }
} else {
    item.deadline_detected = null;
}

/* ---------------- Reason ---------------- */

if (typeof item.reason !== "string" || item.reason.trim() === "") {
    warnings.push("Missing reason.");
    item.reason = "No reason generated.";
}

/* ---------------- Summary ---------------- */

if (typeof item.summary !== "string" || item.summary.trim() === "") {
    warnings.push("Missing summary.");
    item.summary = "No summary generated.";
}

/* ---------------- Promotion Detection (Warning Only) ---------------- */

const emailText = `
${item.subject || ""}
${item.email_body_clean || ""}
`.toLowerCase();

const promotionKeywords = [
    "discount",
    "offer",
    "off",
    "sale",
    "deal",
    "coupon",
    "limited time",
    "buy now",
    "claim",
    "save",
    "%",
    "upgrade",
    "premium"
];

const looksLikePromotion =
    promotionKeywords.some(word => emailText.includes(word));

if (looksLikePromotion && item.category !== "PROMOTION") {
    warnings.push(
        "Email appears promotional but AI classified it as " + item.category
    );
}

/* ---------------- Final ---------------- */

const validationPassed =
    errors.length === 0;

return {
    json: {
        ...item,
        urgency_score: urgency,
        validation_passed: validationPassed,
        validation_errors: errors,
        validation_warnings: warnings
    }
};

const item = $input.first().json;

const CATEGORY = (item.category || "OTHER").toUpperCase();
const IMPORTANCE = (item.importance || "MEDIUM").toUpperCase();
const URGENCY = Number(item.urgency_score || 5);

const actionPlan = {
  labels_to_apply: [],
  mark_important: false,
  star_email: false,
  archive_email: false,
  mark_read: false,
  trigger_urgent_notification: false,
  create_calendar_event: false,
  generate_reply_draft: false
};

const addLabel = (label) => {
  if (!actionPlan.labels_to_apply.includes(label)) {
    actionPlan.labels_to_apply.push(label);
  }
};

// ---------- Category ----------

switch (CATEGORY) {

  case "CAREER":
    addLabel("AI/Career");

    if (item.action_required)
      addLabel("AI/ActionRequired");

    if (item.deadline_detected)
      actionPlan.create_calendar_event = true;

    break;

  case "COLLEGE":
    addLabel("AI/College");

    if (item.action_required)
      addLabel("AI/ActionRequired");

    if (item.deadline_detected)
      actionPlan.create_calendar_event = true;

    break;

  case "FINANCE":
    addLabel("AI/Finance");

    if (item.action_required)
      addLabel("AI/ActionRequired");

    break;

  case "PERSONAL":
    addLabel("AI/Personal");
    break;

  case "PROMOTION":
    addLabel("AI/Promotion");

    actionPlan.archive_email = true;
    actionPlan.mark_read = true;

    break;

  case "NEWSLETTER":
    addLabel("AI/Newsletter");

    actionPlan.archive_email = true;

    break;

  case "AUTOMATED":
    addLabel("AI/Automated");

    if (!item.action_required)
      actionPlan.archive_email = true;

    break;

  default:
    addLabel("AI/Other");
}

// ---------- Importance ----------

if (IMPORTANCE === "HIGH") {

  addLabel("AI/Urgent");

  actionPlan.mark_important = true;
  actionPlan.star_email = true;

  if (URGENCY >= 8)
    actionPlan.trigger_urgent_notification = true;
}

if (IMPORTANCE === "MEDIUM") {

  if (URGENCY >= 7)
    actionPlan.star_email = true;
}

// ---------- Edge Cases ----------

// High urgency but AI forgot HIGH importance

if (URGENCY >= 9 && IMPORTANCE !== "HIGH") {

  actionPlan.mark_important = true;
  actionPlan.star_email = true;

  addLabel("AI/Urgent");
}

// Deadline always deserves ActionRequired

if (item.deadline_detected) {

  addLabel("AI/ActionRequired");
}

// Promotional emails should never notify

if (
  CATEGORY === "PROMOTION" ||
  CATEGORY === "NEWSLETTER"
) {
  actionPlan.trigger_urgent_notification = false;
}

// Parse failed

if (item.parse_error) {

  addLabel("AI/NeedsReview");

  actionPlan.archive_email = false;
  actionPlan.mark_read = false;
}

// Validation failed

if (!item.validation_passed) {

  addLabel("AI/NeedsReview");

  actionPlan.archive_email = false;
  actionPlan.trigger_urgent_notification = false;
}

return {
  json: {
    ...item,
    action_plan: actionPlan
  }
};

const labelItems = $input.all().map(item => item.json);
const labelMap = {};
labelItems.forEach(l => { labelMap[l.name] = l.id; });

const decisionData = $('Decision Engine').first().json;

// Resolve our custom AI/* labels
const customLabelIds = decisionData.action_plan.labels_to_apply
  .map(name => labelMap[name])
  .filter(id => id !== undefined);

// System labels are always fixed IDs in Gmail — no lookup needed
const SYSTEM_LABELS = { IMPORTANT: "IMPORTANT", STARRED: "STARRED", INBOX: "INBOX" };

const labelsToAdd = [...customLabelIds];
if (decisionData.action_plan.mark_important) labelsToAdd.push(SYSTEM_LABELS.IMPORTANT);
if (decisionData.action_plan.star_email) labelsToAdd.push(SYSTEM_LABELS.STARRED);

return {
  json: {
    ...decisionData,
    labels_to_add: [...new Set(labelsToAdd)],
    labels_to_remove: decisionData.action_plan.archive_email ? [SYSTEM_LABELS.INBOX] : []
  }
};

const output = [];

const importantDomains = [
  "careers.google.com", "linkedin.com", "internshala.com",
  "naukri.com", "hackerrank.com", "leetcode.com", "github.com",
  "unstop.com", "unstop.news",
  "codeforces.com", "codechef.com", "atcoder.jp",
  "hackerearth.com", "topcoder.com", "geeksforgeeks.org",
  "leetcode.com", "spoj.com", "codingninjas.com"
];

const promotionKeywords = [
  "50% off", "discount", "limited-time", "limited time", "sale",
  "coupon", "deal", "buy now", "claim now", "special offer",
  "exclusive offer", "save big", "offer ends", "upgrade now",
  "get premium", "unsubscribe", "learn more"
];

function htmlToText(html) {
  if (!html) return '';
  return html
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<\/div>/gi, '\n')
    .replace(/<\/tr>/gi, '\n')
    .replace(/<[^>]+>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#\d+;/g, '')
    .replace(/&[a-zA-Z]+;/g, '')
    .replace(/[ \t]{2,}/g, ' ')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function stripBrokenIcons(text) {
  return text
    .replace(/[\u{1F300}-\u{1FAFF}\u{2600}-\u{27BF}\u{2190}-\u{21FF}\u{2B00}-\u{2BFF}]/gu, '')
    .replace(/[\uFFFD]/g, '')
    .replace(/\s{2,}/g, ' ')
    .trim();
}

// Strip long tracking URLs (Spotify-style) before keyword/AI processing — noise reduction
function stripLongUrls(text) {
  return text.replace(/https?:\/\/\S{40,}/g, '[link]');
}

for (const item of $input.all()) {
  const raw = item.json;

  const senderEmail = (raw.from?.value?.[0]?.address || "").toLowerCase();
  const senderName = raw.from?.value?.[0]?.name || "";
  const subject = (raw.subject || "").trim();
  const labels = raw.labelIds || [];

  let bodyText = (raw.text || '').trim();
  let bodySource = 'text';

  if (!bodyText || bodyText.length < 20) {
    if (raw.html) {
      bodyText = htmlToText(raw.html);
      bodySource = 'html_stripped';
    }
  }
  if (!bodyText || bodyText.length < 5) {
    bodyText = raw.snippet || '';
    bodySource = 'snippet_fallback';
  }
  bodyText = stripBrokenIcons(stripLongUrls(bodyText));

  // Gmail's label is now just a HINT passed to the AI, not a skip trigger
  const gmailCategoryHint = labels.find(l => l.startsWith('CATEGORY_')) || null;

  // Only strong keyword evidence triggers a hard skip
  const searchText = `${subject} ${bodyText}`.toLowerCase();
  const obviousPromotion = promotionKeywords.some(keyword => searchText.includes(keyword));
  const trustedSender = importantDomains.some(domain => senderEmail.includes(domain));
  const skipAI = obviousPromotion && !trustedSender;

  output.push({
    json: {
      message_id: raw.id,
      thread_id: raw.threadId,
      sender_name: senderName,
      sender_email: senderEmail,
      subject,
      email_body_clean: bodyText,
      body_source: bodySource,
      gmail_category_hint: gmailCategoryHint,
      received_at: raw.date,
      existing_labels: labels,
      skip_ai: skipAI
    }
  });
}

return output;

const httpResponse = $input.first().json;
const prevData = $("Extract email data").first().json;

let parsed;
try {
  const rawContent = httpResponse.choices[0].message.content;
  parsed = JSON.parse(rawContent);
} catch (err) {
  const errorMessage = err instanceof Error ? err.message : String(err);
  return {
    json: {
      parse_error: true,
      parse_error_message: errorMessage,
      raw_content: httpResponse?.choices?.[0]?.message?.content ?? null,
      message_id: prevData.message_id,
      thread_id: prevData.thread_id
    }
  };
}

return {
  json: {
    message_id: prevData.message_id,
    thread_id: prevData.thread_id,
    sender_name: prevData.sender_name,
    sender_email: prevData.sender_email,
    subject: prevData.subject,
    existing_labels: prevData.existing_labels,
    category: parsed.category,
    importance: parsed.importance,
    urgency_score: parsed.urgency_score,
    action_required: parsed.action_required,
    deadline_detected: parsed.deadline_detected,
    reason: parsed.reason,
    summary: parsed.summary,
    event_datetime : parsed.event_datetime,
    event_type : parsed.event_type, 
    parse_error: false
  }
};

const item = $input.first().json;

const message = `🔔 *Action Required*
*${item.category}* | Urgency: ${item.urgency_score}/10
*${item.subject}*
From: ${item.sender_name}
${item.deadline_detected ? `⏰ Deadline: ${item.deadline_detected}` : ''}
${item.summary}`;

return {
  json: {
    ...item,
    telegram_text: message
  }
};
